 		cap.stop(t)
+		dnsCap.stop(t)
 		t.Fatalf("wanbond capture: non-positive throughput %.2f Mbit/s", mbps)
 	}
 	cap.stop(t)
+	dnsCap.stop(t)

 	if fi, err := os.Stat(pcapFile); err != nil || fi.Size() == 0 {
